import { sendSignerCommand, signerClientTimeoutMs, signerSocketPath } from "../executor/signer/client.mjs";

const LIFI_INTENT = {
  schemaVersion: 1,
  intentType: "lifi_bridge",
  strategyId: "lifi-bridge",
  chain: "base",
  amountUsd: 6.9,
  mode: "live",
  observedAt: new Date().toISOString(),
  quote: {
    observedAt: new Date().toISOString(),
    toAmount: "2865576493710813",
    fromAmount: "3000000000000000",
    fromChain: "8453",
    toChain: "1",
    integrator: "bob-claw",
  },
  tx: {
    to: "0x1231DEB6f5749EF6cE6943a275A1D3E7486F4EaE",
    data: "",
    value: "0xaa87bee538000",
    gasLimit: "0xfe204",
    chainId: 8453,
  },
};

async function main() {
  console.log("Executing Li.FI Base ETH → Ethereum ETH bridge...");
  console.log("Source: Base 0.003 ETH (~$6.90)");
  console.log("Expected destination: Ethereum 0.002865 ETH (~$6.59)");
  console.log("Fee: ~$0.31 + Base gas ~$0.01");
  console.log("");

  const result = await sendSignerCommand({
    message: {
      command: "sign_and_broadcast",
      intent: LIFI_INTENT,
      awaitConfirmation: true,
      confirmations: 1,
      timeoutMs: 120_000,
    },
    socketPath: signerSocketPath(),
    timeoutMs: signerClientTimeoutMs(),
  });

  console.log("Signer result:", result.status);
  if (result.broadcast?.txHash) {
    console.log("Base tx:", result.broadcast.txHash);
  }
  if (result.receipt) {
    console.log("Receipt:", JSON.stringify(result.receipt, null, 2));
  }
  if (result.error) {
    console.error("Error:", result.error.message);
    process.exitCode = 1;
  }
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});
